INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '6627f82c-cfef-4988-b174-de376ed169fa',
  '00000000-0000-0000-0000-000000000001',
  $escape$Kotlin BE Type Safety — Nullability, Inference, and Reified Generics That Actually Work$escape$,
  $escape$Kotlin's type system eliminates entire categories of runtime failures before your service ever starts. Unlike Java's raw generics (erased at runtime), Kotlin gives you `reified` type parameters in `inline` functions — meaning you can call `T::class` inside a generic and the JVM won't lose that information. This is a game-changer for building generic repository layers or deserializing responses without passing `Class<T>` explicitly. The compiler also enforces nullability at the call site: `String` and `String?` are distinct types, so a Ktor route handler or a Spring service method that returns `UserResponse` cannot silently return null without a compile error. Type inference keeps the verbosity down — `val user = userRepository.findById(id)` resolves to `User?` automatically, and the compiler forces you to handle the null branch before accessing any property. Compared to dynamically typed languages like Python or JavaScript (even with TypeScript), Kotlin's guarantees hold at compile time, not just at the linter level. For backend services handling hundreds of concurrent requests, this means fewer defensive null-checks cluttering your business logic and fewer production NPEs sneaking through.$escape$,
  $escape$// Reified generic: no Class<T> parameter needed
inline fun <reified T> ObjectMapper.parseResponse(json: String): T =
    readValue(json, T::class.java)

// Usage — type inferred, null-safe
val response: ApiResponse = mapper.parseResponse(rawJson)

// Nullable vs non-nullable enforced at compile time
fun findUser(id: UUID): User? = userRepository.findByIdOrNull(id)

fun getUsername(id: UUID): String {
    val user = findUser(id) ?: throw NotFoundException("User $id not found")
    return user.name  // smart-cast: user is User here, not User?
}$escape$,
