INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '1a037757-112f-4533-b7f2-6af36e0e64f0',
  '00000000-0000-0000-0000-000000000001',
  $escape$Kotlin Backend — Gradle Lock Files, Version Catalogs, and CVE Auditing$escape$,
  $escape$Gradle's dependency locking pins your entire resolved graph — including transitives — into files under `gradle/dependency-locks/`. Without it, `implementation("org.springframework.boot:spring-boot-starter:3.+")` resolves differently on every CI run. Enable locking in `build.gradle.kts` with `dependencyLocking { lockAllConfigurations() }`, then generate locks via `./gradlew dependencies --write-locks`. Commit these files; any PR that touches them signals a dependency change worth reviewing.

For centralized versioning, Gradle's Version Catalog (`gradle/libs.versions.toml`) eliminates scattered string literals across multi-module builds. Declare versions once and reference them as `libs.spring.boot.starter.web` in every subproject's DSL.

For security auditing, the OWASP Dependency-Check plugin scans your resolved classpath against the NVD CVE database. Set `failBuildOnCVSS = 7.0f` to block builds with high-severity vulnerabilities. Pair it with the Ben Manes Versions plugin (`./gradlew dependencyUpdates`) to surface outdated artifacts with available upgrades. Running both in CI gives you reproducible, auditable, and vulnerability-gated Kotlin backend builds without manual version tracking.$escape$,
  $escape$plugins {
    id("org.owasp.dependencycheck") version "9.0.9"
    id("com.github.ben-manes.versions") version "0.51.0"
}

dependencyLocking {
    lockAllConfigurations()
}

dependencies {
    implementation(libs.spring.boot.starter.web)
    implementation(libs.kotlin.reflect)
}

dependencyCheck {
    failBuildOnCVSS = 7.0f
    suppressionFile = "config/owasp-suppressions.xml"
}$escape$,
  $escape$kotlin$escape$,
