INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '48d33861-216a-406e-b385-6710a1b655cf',
  '00000000-0000-0000-0000-000000000001',
  $escape$Kotlin BE Benchmarking — JMH + kotlinx.benchmark in Practice$escape$,
  $escape$Kotlin on the JVM inherits JIT warmup costs that make naive timing (`System.nanoTime()`) unreliable. Use `kotlinx.benchmark` — a Kotlin-idiomatic wrapper around JMH — to get statistically valid results. Annotate your class with `@State(Scope.Benchmark)` and mark hot paths with `@Benchmark`. The JMH harness handles fork counts, warmup iterations, and dead-code elimination via `Blackhole`. For coroutine-heavy code, suspend functions can't be benchmarked directly inside JMH; wrap them with `runBlocking` and measure the full dispatch overhead including `Dispatchers.Default` thread-pool contention. Use `@BenchmarkMode(Mode.AverageTime)` with `@OutputTimeUnit(TimeUnit.MICROSECONDS)` for I/O-bound suspend benchmarks. Profile JVM hotspots with async-profiler (`-agentpath`) attached to a running Ktor or Spring Boot instance — it captures CPU flame graphs without safepoint bias. Inline functions (`inline fun`) and reified generics eliminate call overhead at compile time; verify with `@Benchmark` before assuming savings. Always run with `-XX:+UseG1GC` matching your prod JVM flags or results are misleading.$escape$,
  $escape$import kotlinx.benchmark.*
import org.openjdk.jmh.annotations.*
import kotlinx.coroutines.runBlocking
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.withContext

@State(Scope.Benchmark)
@BenchmarkMode(Mode.AverageTime)
@OutputTimeUnit(TimeUnit.MICROSECONDS)
@Warmup(iterations = 3, time = 1)
@Measurement(iterations = 5, time = 1)
@Fork(2)
open class CoroutineBenchmark {

    @Benchmark
    fun dispatchToDefault(): String = runBlocking {
        withContext(Dispatchers.Default) { "computed" }
    }
}$escape$,
  $escape$kotlin$escape$,
