INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '13394105-dec9-4675-9912-550b7b7cc269',
  '00000000-0000-0000-0000-000000000001',
  $escape$Kotlin Backend — Unit Testing with JUnit 5 and MockK$escape$,
  $escape$Kotlin backend services on the JVM use JUnit 5 as the standard test runner, paired with MockK — the idiomatic Kotlin mocking library that understands data classes, coroutines, and extension functions out of the box. Unlike Mockito, MockK handles `suspend` functions natively via `coEvery` and `coVerify`, making it essential for coroutine-based service layers.

The core philosophy: test behavior, not implementation. Mock only external dependencies (repositories, HTTP clients), never internal logic. Use `@ExtendWith(MockKExtension::class)` to wire MockK with JUnit 5 without boilerplate setup.

For Ktor or Spring Boot backends, keep unit tests focused on service/domain classes. Use `relaxed = true` mocks sparingly — prefer explicit `every { }` stubs to document expected contracts. Name tests with backtick strings for readability. Run the full suite with `./gradlew test`; JUnit 5's `@Nested` classes help group related scenarios without separate files. Aim for fast, deterministic tests that don't touch the database or network — those belong in integration tests.$escape$,
  $escape$import io.mockk.*
import io.mockk.impl.annotations.MockK
import kotlinx.coroutines.test.runTest
import org.junit.jupiter.api.extension.ExtendWith
import kotlin.test.Test
import kotlin.test.assertEquals

@ExtendWith(MockKExtension::class)
class ArticleServiceTest {

    @MockK lateinit var repo: ArticleRepository
    private val service by lazy { ArticleService(repo) }

    @Test
    fun `returns published articles sorted by date`() = runTest {
        coEvery { repo.findByStatus(ArticleStatus.PUBLISHED) } returns listOf(
            Article(id = 1, title = "Kotlin Flows", publishedAt = now()),
            Article(id = 2, title = "Coroutines Deep Dive", publishedAt = now().minusDays(1))
        )

        val result = service.getPublished()

        assertEquals(1, result.first().id)
        coVerify(exactly = 1) { repo.findByStatus(ArticleStatus.PUBLISHED) }
    }
}$escape$,
  $escape$kotlin$escape$,
