INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '6cd382d2-10ea-49e1-861d-d656d8abde6a',
  '00000000-0000-0000-0000-000000000001',
  $escape$Kotlin Backend Code Quality — Detekt, ktlint, and Idiomatic Patterns$escape$,
  $escape$Detekt and ktlint are the two pillars of Kotlin backend code quality. ktlint enforces formatting (indentation, trailing commas, import ordering) with zero configuration via the Kotlin official style guide. Detekt handles static analysis — complexity thresholds, naming conventions, and anti-patterns like `MagicNumber` or `LongParameterList`. Run both in CI via Gradle. For idiomatic Kotlin, prefer `data class` over manually implemented POJOs, use `sealed class` for exhaustive result types instead of nullable returns, and leverage `apply`, `let`, and `run` scope functions to reduce boilerplate initialization blocks. Replace checked-null chains with `?.let { }` and `?: return`. In Ktor or Spring Boot controllers, use `require()` and `check()` for precondition validation instead of manual `if/throw` blocks — they're self-documenting and throw `IllegalArgumentException`/`IllegalStateException` respectively. Configure Detekt with a `detekt.yml` baseline to suppress existing violations while enforcing rules on new code, enabling incremental adoption without blocking builds.$escape$,
  $escape$// detekt + idiomatic Kotlin patterns
sealed class Result<out T> {
    data class Success<T>(val data: T) : Result<T>()
    data class Failure(val error: String) : Result<Nothing>()
}

fun findUser(id: String): Result<User> {
    require(id.isNotBlank()) { "User ID must not be blank" }
    return userRepository.findById(id)
        ?.let { Result.Success(it) }
        ?: Result.Failure("User $id not found")
}

// ktlint enforces trailing comma in multi-line params
data class UserRequest(
    val name: String,
    val email: String,
    val role: Role,
)$escape$,
  $escape$kotlin$escape$,
