INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'b3430936-5e78-424a-aa2d-2926a9835695',
  '00000000-0000-0000-0000-000000000001',
  $escape$Kotlin Backend Security — Null Safety, Injection Guards, and OWASP CVE Scanning$escape$,
  $escape$Kotlin's type system eliminates null-pointer vulnerabilities by making nullability explicit — `String?` vs `String` enforced at compile time, not runtime. But JVM memory safety doesn't protect against injection or vulnerable transitive dependencies. For SQL injection, use Exposed DSL or Spring Data's `@Query` with named parameters — never string interpolation in raw JDBC calls. In Ktor, validate all incoming request bodies with `call.receive<T>()` backed by data classes; enable Kotlinx serialization strict mode (`ignoreUnknownKeys = false`) to reject unexpected fields that could smuggle malicious payloads. For dependency vulnerability scanning, add the OWASP Dependency-Check Gradle plugin and configure `failBuildOnCVSS = 7.0f` to hard-fail CI on high-severity CVEs. Run `./gradlew dependencyCheckAnalyze` locally before pushing. Also add the Gradle Versions Plugin (`dependencyUpdates` task) to surface outdated transitive deps proactively. Avoid bare `catch (e: Exception) {}` blocks — they swallow security-relevant exceptions and mask exploitable error paths in your Ktor pipeline.$escape$,
  $escape$// build.gradle.kts — OWASP CVE scanning
plugins {
    id("org.owasp.dependencycheck") version "9.2.0"
}
dependencyCheck {
    failBuildOnCVSS = 7.0f
    suppressionFile = "owasp-suppressions.xml"
    analyzers.assemblyEnabled = false
}

// Exposed DSL — injection-safe parameterized query
fun findUserByEmail(db: Database, email: String): User? =
    transaction(db) {
        Users.select { Users.email eq email }
            .singleOrNull()
            ?.toUser()
    }$escape$,
  $escape$kotlin$escape$,
