INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '36a8e5e8-c82b-42b1-a693-c5f4be755ac3',
  '00000000-0000-0000-0000-000000000001',
  $escape$Kotlin Backend Deployment — Shrinking JARs, Containers, and Going Native$escape$,
  $escape$A standard Kotlin + Ktor or Spring Boot fat JAR balloons to 20–80 MB because it bundles the entire runtime. For containers, this inflates image layers and cold-start latency. Use multi-stage Docker builds: compile in a full JDK image, copy only the JAR into a slim `eclipse-temurin:21-jre-alpine` base — cutting image size by ~60%. For zero-JVM deploys, GraalVM Native Image compiles your Kotlin app to a self-contained binary under 50 MB with sub-50ms startup. Configure it via the `org.graalvm.buildtools.native` Gradle plugin. Ktor ships first-class native support; Spring Boot 3.x works via AOT processing with `processAot` + `nativeCompile` tasks. Watch for reflection-heavy libraries (Jackson, Hibernate) — register classes in `reflect-config.json` or switch to kotlinx.serialization, which is reflection-free and native-friendly. For Lambda or Cloud Run, native image is worth the 5-minute compile cost: no JVM warmup, predictable latency from request one.$escape$,
  $escape$// build.gradle.kts — GraalVM native + slim Docker target
plugins {
    kotlin("jvm") version "2.0.0"
    id("org.graalvm.buildtools.native") version "0.10.2"
    application
}

graalvmNative {
    binaries {
        named("main") {
            imageName.set("app")
            buildArgs.add("--no-fallback")
            buildArgs.add("-H:+ReportExceptionStackTraces")
        }
    }
}

// Dockerfile (multi-stage)
// FROM ghcr.io/graalvm/native-image:21 AS build
// COPY . . && RUN ./gradlew nativeCompile
// FROM debian:bookworm-slim
// COPY --from=build build/native/nativeCompile/app /app
// ENTRYPOINT ["/app"]$escape$,
  $escape$kotlin$escape$,
