INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '6efa285a-ae7e-4365-b5d7-20b86a0d9385',
  '00000000-0000-0000-0000-000000000001',
  $escape$Kotlin Backend Coroutines — Structured Concurrency with supervisorScope vs coroutineScope$escape$,
  $escape$Kotlin's coroutines give backend services fine-grained control over failure propagation — something threads never could. `coroutineScope` uses cooperative cancellation: if one child fails, the entire scope and its siblings are cancelled. `supervisorScope` isolates failures — a failing child doesn't tear down its siblings. In a Ktor or Spring WebFlux handler making parallel downstream calls, the choice is critical. Use `coroutineScope` when all results are required (e.g., assembling a composite response — one failure means the whole response is invalid). Use `supervisorScope` when partial results are acceptable (e.g., enriching a feed with optional metadata). Under the hood, Kotlin's coroutine dispatcher maps lightweight coroutines onto a thread pool via `Dispatchers.IO` for blocking calls and `Dispatchers.Default` for CPU-bound work. Unlike the JVM thread-per-request model, thousands of suspended coroutines cost only heap memory — no stack allocation. Always launch structured coroutines inside a scope tied to a request lifecycle to prevent leaks. Avoid `GlobalScope` in production — it escapes structured concurrency entirely and makes cancellation impossible.$escape$,
  $escape$import kotlinx.coroutines.*

suspend fun fetchUserProfile(userId: String): UserProfile = supervisorScope {
    val coreData = async { userService.getCoreData(userId) }
    val badges = async { badgeService.getBadges(userId) }  // optional enrichment
    val streak = async { streakService.getStreak(userId) } // optional enrichment

    val core = coreData.await() // throws if core fails — propagates up
    UserProfile(
        core = core,
        badges = runCatching { badges.await() }.getOrNull(),
        streak = runCatching { streak.await() }.getOrNull()
    )
}$escape$,
  $escape$kotlin$escape$,
