INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '01fe26a0-97ae-4879-ad11-66992658b4e0',
  '00000000-0000-0000-0000-000000000001',
  $escape$Kotlin Backend — Monitoring JVM GC Pauses and Runtime Metrics in Production$escape$,
  $escape$On Kotlin backends running on the JVM, untracked GC pauses are silent latency killers. Micrometer, bundled with Spring Boot Actuator, exposes `jvm.gc.pause` timers out of the box — but you need to bind `JvmGcMetrics` explicitly if you're not using Spring Boot autoconfiguration. GC pause data surfaces as a `Timer` with tags for `action` (e.g. `end of minor GC`) and `cause` (e.g. `G1 Evacuation Pause`). For production profiling without agents, enable JDK Flight Recorder via `-XX:StartFlightRecording=filename=app.jfr,settings=profile` and parse with `jfr print`. Switching to ZGC (`-XX:+UseZGC`) reduces stop-the-world pauses to sub-millisecond, measurable via `jvm.gc.pause` max values dropping in your Prometheus/Grafana dashboards. Pair this with `jvm.memory.used{area="heap"}` and `jvm.threads.live` to correlate heap pressure with pause spikes. Set Micrometer histogram percentiles on GC pause to catch p99 outliers before users do.$escape$,
  $escape$import io.micrometer.core.instrument.MeterRegistry
import io.micrometer.core.instrument.binder.jvm.JvmGcMetrics
import io.micrometer.core.instrument.binder.jvm.JvmMemoryMetrics
import io.micrometer.core.instrument.binder.jvm.JvmThreadMetrics
import org.springframework.context.annotation.Bean
import org.springframework.context.annotation.Configuration

@Configuration
class MetricsConfig {
    @Bean
    fun jvmGcMetrics(registry: MeterRegistry): JvmGcMetrics =
        JvmGcMetrics().also {
            it.bindTo(registry)
            JvmMemoryMetrics().bindTo(registry)
            JvmThreadMetrics().bindTo(registry)
        }
}$escape$,
  $escape$kotlin$escape$,
