INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '2840078c-a750-42d0-96c6-5d058d0afbbd',
  '00000000-0000-0000-0000-000000000001',
  $escape$Kotlin Backend — Where It Shines and Where It Struggles$escape$,
  $escape$Kotlin on the backend excels in JVM-heavy enterprises migrating from Java. Its null safety eliminates NPEs at compile time, and coroutines handle thousands of concurrent I/O-bound requests with structured concurrency — far cleaner than Java's thread-per-request model. Spring Boot + Kotlin's extension functions and data classes slash boilerplate: a JPA entity with equals/hashCode/toString is one line. Ktor's DSL suits microservices needing a lightweight, non-Spring footprint. Sealed classes make exhaustive domain modeling (Result<T>, Either<L,R>) idiomatic, catching unhandled states at compile time.

Where Kotlin struggles: cold-start latency on AWS Lambda/GraalVM native image support lags behind Go or Rust — GraalVM reflection config for Kotlin metadata is painful. Annotation processing (kapt) is slower than Java's APT and blocks incremental compilation. If your team is Python-native or your service is CPU-bound numerical work, Kotlin adds JVM overhead with no ergonomic payoff. For CLI tooling or system-level code, Go's single binary and sub-second build times win decisively.$escape$,
  $escape$// Structured concurrency + sealed Result — idiomatic Kotlin backend
sealed class ApiResult<out T>
data class Success<T>(val data: T) : ApiResult<T>()
data class Failure(val error: String) : ApiResult<Nothing>()

suspend fun fetchUser(id: Long): ApiResult<User> = coroutineScope {
    val user = async { userRepository.findById(id) }
    val prefs = async { prefsRepository.findByUserId(id) }
    user.await()?.let { Success(it.copy(prefs = prefs.await())) }
        ?: Failure("User $id not found")
}

// Caller is forced to handle both branches
when (val result = fetchUser(42)) {
    is Success -> respond(result.data)
    is Failure -> respondError(result.error)
}$escape$,
  $escape$kotlin$escape$,
